def write_artifact(target: Path, heading: str, content: str) -> None:
    slug = target.stem
    section_file = SECTIONS / f"{slug}.body.md"
    manifest = SECTIONS / f"{slug}.manifest.json"
    section_file.parent.mkdir(parents=True, exist_ok=True)
    section_file.write_text(content.rstrip() + "\n", encoding="utf-8", newline="\n")
    manifest.write_text(json.dumps({"target_path": str(target), "sections": [{"level": 1, "heading": heading, "content_file": section_file.name}]}, ensure_ascii=False, indent=2), encoding="utf-8", newline="\n")
    subprocess.run([sys.executable, str(ROOT / "scripts" / "write_artifact_sections.py"), "--manifest", str(manifest)], check=True, cwd=ROOT)


